// Format finished goods label: PRODUCTO ANCHO×LARGO×MICMiC - CLIENTE
// Video de login: se carga desde Firebase settings.loginVideo
const formatFGLabel = (item) => {
  if (!item) return '';
  // Si el producto tiene texto personalizado que ya incluye dimensiones, úsalo directamente
  // pero limpia duplicados como "EMBUTIDOS 2 KIRI - 53X83X12MIC - 53X83X12MIC"
  let cat = (item.producto || item.categoria || item.desc || '').toUpperCase();

  // Quitar info del cliente que pueda estar pegada
  cat = cat.split(' - INVERSIONES')[0]
           .split(' | NATURAL')[0]
           .split(' - NATURAL')[0]
           .trim();

  const ancho = parseFloat(item.ancho || 0);
  const largo = parseFloat(item.largo || 0);
  let micras = parseFloat(item.micras || 0);
  if (micras > 0 && micras < 1) micras = Math.round(micras * 1000);

  const dims = (ancho > 0 || largo > 0) ? `${ancho}X${largo}X${micras}MIC` : '';

  if (!dims) return cat;

  // Si la categoría ya termina con las mismas dimensiones, no las dupliques
  if (cat.endsWith(dims) || cat.includes(` - ${dims}`) || cat.includes(`-${dims}`)) {
    // Remover duplicado al final si existe
    const withoutDup = cat.replace(new RegExp(`(\\s*-\\s*${dims.replace(/\//g,'\\/')})+$`), '').trim();
    return `${withoutDup} - ${dims}`;
  }

  return `${cat} - ${dims}`;
};
const detectSubcategory = (code, desc) => {
  const c = ((code||'')+(desc||'')).toUpperCase();
  if (/STRECTH|STRECH|STRETCH|STREFIL|ENTREFIL|SFM-|SFA-|OSFA|SFJUMBO|PSFM|STRETCH FILM/.test(c)) return 'Stretch Film';
  if (/CINTA|CINTA DE EMBALAR/.test(c)) return 'Cintas';
  if (/PAPEL KRAFT|KRAFT/.test(c)) return 'Papel Kraft';
  if (/DISPEN|DISPENSADOR/.test(c)) return 'Dispensadores';
  if (/BOL-|BOLSA|EMBUTID|EMPAQUE|LAMINA|PAÑAL|FG-[A-Z]/.test(c) && !/TERMO|STRETCH|STRECTH|CINTA|KRAFT|DISPEN/.test(c)) return 'Bolsas Plásticas';
  if (/TERMO|THERMO|SHRINK|ENCOG/.test(c)) return 'Termoencogibles';
  return '';
};
const cleanFGCode = (id) => {
  if(!id) return '';
  // Strip all suffixes: ___ALMACEN-*, -RESTORE, -BACKUP, -COPY, _inv, then normalize separators
  let c = (id||'').split('___')[0];
  c = c.replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/-COPY\d*$/i,'').replace(/_inv$/i,'');
  c = c.replace(/\s+/g,'').trim();
  return c;
};
const getItemSubcategory = (item) => (item && (item.subcategory || detectSubcategory(item.id || item.displayId || '', item.desc || ''))) || '';

const parseNum = (val) => {
  if (!val) return 0;
  if (typeof val === 'number') return val;
  let str = String(val || '').trim();
  if (str.includes('.') && str.includes(',')) str = str.replace(/\./g, '').replace(',', '.');
  else if (str.includes(',')) str = str.replace(',', '.');
  const parsed = parseFloat(str);
  return isNaN(parsed) ? 0 : parsed;
};
const getSafeDate = (ts) => {
  if (!ts) return '';
  if (typeof ts === 'string') return ts;
  if (typeof ts.toDate === 'function') return ts.toDate().toLocaleDateString('es-VE');
  if (typeof ts === 'number') return new Date(ts).toLocaleDateString('es-VE');
  if (ts instanceof Date) return ts.toLocaleDateString('es-VE');
  return '';
};

