// Genera el objeto de permisos por defecto (todos en false) desde SYSTEM_MODULES
const generateDefaultPermissions = () => {
  const perms = {};
  SYSTEM_MODULES.forEach(mod => {
    perms[mod.id] = false;
    mod.submodules.forEach(sub => { perms[sub.id] = false; });
  });
  return perms;
};

