  const handleExportExcel = (tableDataOrId, filename, headers = null) => {
    if (typeof tableDataOrId === 'string') {
      const table = document.getElementById(tableDataOrId); if (!table) return; const tableClone = table.cloneNode(true);
      const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8" /><style>table{border-collapse:collapse;width:100%;font-family:Arial;font-size:11px;}th,td{border:1px solid #000;padding:5px;}th{text-align:center;}</style></head><body><h2>SERVICIOS JIRET G&B, C.A. - RIF: J-412309374</h2><br/>${tableClone.outerHTML}</body></html>`;
      const blob = new Blob([html], { type: 'application/vnd.ms-excel' }); const url = URL.createObjectURL(blob); const link = document.createElement('a'); link.href = url; link.download = `${filename}_${getTodayDate()}.xls`; document.body.appendChild(link); link.click(); document.body.removeChild(link);
    } else if (Array.isArray(tableDataOrId)) {
      // Export directly from data array using custom HTML logic
      let html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8" /><style>table{border-collapse:collapse;width:100%;font-family:Arial;font-size:11px;}th,td{border:1px solid #000;padding:5px;}th{background-color:#f3f4f6;text-align:center;font-weight:bold;}</style></head><body><h2>SERVICIOS JIRET G&B, C.A. - RIF: J-412309374</h2><br/><table>`;
      if (headers) {
        html += `<thead><tr>${headers.map(h => `<th>${h}</th>`).join('')}</tr></thead>`;
      }
      html += `<tbody>${tableDataOrId.map(row => `<tr>${row.map(cell => `<td>${cell}</td>`).join('')}</tr>`).join('')}</tbody></table></body></html>`;
      const blob = new Blob([html], { type: 'application/vnd.ms-excel' }); const url = URL.createObjectURL(blob); const link = document.createElement('a'); link.href = url; link.download = `${filename}_${getTodayDate()}.xls`; document.body.appendChild(link); link.click(); document.body.removeChild(link);
    }
  };

  const exportTomaFisicaExcel = () => {
    const today = getTodayDate();
    const sectionHeader = (label, color='#2d3748') =>
      `<tr><td colspan="10" style="background-color:${color};color:#fff;font-weight:bold;text-align:center;padding:6px;font-size:11px;">${label}</td></tr>`;

    const itemRow = (id, desc, unit, stock, altBg='') => `<tr>
      <td style="${altBg}">${id}</td>
      <td style="${altBg}">${desc.toUpperCase()}</td>
      <td style="text-align:center;${altBg}">${unit || 'KG'}</td>
      <td style="text-align:right;${altBg}">${formatNum(stock)}</td>
      <td style="background-color:#ffffcc;"></td>
      <td style="background-color:#ffffcc;"></td>
      <td style="background-color:#ffffcc;"></td>
      <td style="background-color:#ffffcc;"></td>
      <td></td>
      <td></td>
    </tr>`;

    let html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
    <head><meta charset="utf-8">
    <style>
      body{font-family:Arial,sans-serif;}
      table{border-collapse:collapse;width:100%;margin:15px 0;}
      th,td{border:1px solid #555;padding:6px 8px;font-size:10px;}
      th{background:#e8e8e8;font-weight:bold;text-align:center;}
    </style></head><body>
    <div style="text-align:center;margin-bottom:16px;">
      <h2 style="margin:4px 0;font-size:14px;">SERVICIOS JIRET G&amp;B, C.A.</h2>
      <p style="margin:2px 0;font-size:11px;"><strong>RIF: J-412309374</strong></p>
      <h3 style="margin:4px 0;font-size:13px;">FORMATO DE TOMA FÍSICA DE INVENTARIO</h3>
      <p style="font-size:11px;"><strong>Fecha:</strong> ${today}</p>
    </div>
    <table>
      <thead><tr>
        <th style="width:11%">Código</th>
        <th style="width:28%">Descripción</th>
        <th style="width:6%">Unidad</th>
        <th style="width:10%">Stock Sistema</th>
        <th style="width:7%">Conteo ZI</th><th style="width:7%">Conteo BQTO</th><th style="width:7%">Conteo C2</th><th style="width:7%">Conteo MCY</th>
        <th style="width:10%">Diferencia</th>
        <th style="width:7%">Por Almacén</th>
      </tr></thead>
      <tbody>`;

    // ── INVENTARIO GENERAL agrupado por categoría, luego subcategoría ──
    const catGroups = {};
    inventory.filter(i=>i.activo!==false).forEach(item => {
      const cat = item.category || 'Otros';
      if (!catGroups[cat]) catGroups[cat] = [];
      catGroups[cat].push(item);
    });

    // Orden preferido de categorías
    const catOrder = ['Materia Prima','Pigmentos','Semielaborados','Consumibles','Herramientas','Tintas','Químicos','Seguridad Industrial','Productos Terminados','Otros'];
    const sortedCats = [...catOrder.filter(c=>catGroups[c]), ...Object.keys(catGroups).filter(c=>!catOrder.includes(c))];

    const catColors = {
      'Materia Prima':'#2d5016','Pigmentos':'#7b3f00','Semielaborados':'#3730a3',
      'Consumibles':'#1e40af','Herramientas':'#92400e','Tintas':'#6d28d9',
      'Químicos':'#065f46','Seguridad Industrial':'#7c3aed','Productos Terminados':'#065f46','Otros':'#374151'
    };

    for (const cat of sortedCats) {
      if (cat === 'Productos Terminados') continue; // se añade en sección propia al final
      const items = catGroups[cat] || [];
      if (items.length === 0) continue;
      html += sectionHeader(`📦 ${cat.toUpperCase()} (${items.length} artículo${items.length!==1?'s':''})`, catColors[cat]||'#374151');
      // Group by subcategory within this category
      const subGroupsGen = {};
      items.forEach(item => {
        const sub = item.subcategory || getItemSubcategory(item) || '';
        const key = sub || '__NONE__';
        if(!subGroupsGen[key]) subGroupsGen[key] = [];
        subGroupsGen[key].push(item);
      });
      const SUB_ORDER_GEN = ['Bolsas Plásticas','Termoencogibles','Stretch Film','Cintas','Papel Kraft','Dispensadores','Empaques Flexibles'];
      const SUB_COLORS_GEN = {'Bolsas Plásticas':'#1d4ed8','Termoencogibles':'#15803d','Stretch Film':'#7c3aed','Cintas':'#92400e','Papel Kraft':'#78350f','Dispensadores':'#9d174d','Empaques Flexibles':'#4338ca'};
      const hasSubs = Object.keys(subGroupsGen).some(k=>k!=='__NONE__');
      const orderedSubsGen = hasSubs
        ? [...SUB_ORDER_GEN.filter(s=>subGroupsGen[s]), ...Object.keys(subGroupsGen).filter(s=>!SUB_ORDER_GEN.includes(s)&&s!=='__NONE__'), ...(subGroupsGen['__NONE__']?['__NONE__']:[])]
        : ['__NONE__'];
      orderedSubsGen.forEach(subKey => {
        const subItems = (subGroupsGen[subKey]||[]).sort((a,b)=>(a.id||'').localeCompare(b.id||''));
        if(hasSubs && subKey !== '__NONE__') {
          html += `<tr><td colspan="10" style="background:${SUB_COLORS_GEN[subKey]||'#374151'};color:#fff;font-weight:bold;padding:3px 8px;font-size:9px;">  ↳ ${subKey.toUpperCase()} — ${subItems.length} art.</td></tr>`;
        }
        subItems.forEach((item, i) => { html += itemRow(item.id, item.desc, item.unit, item.stock, i%2===1?'background-color:#f9f9f9;':''); });
      });
    }

    // ── PRODUCTOS TERMINADOS — por subcategoría, código limpio ──
    // Consolidate inventory PT items by clean code
    const ptByCodeExcel = {};
    inventory.filter(i=>i.category==='Productos Terminados'&&i.activo!==false).forEach(i => {
      // Strip all suffixes and get the canonical clean code
      const rawId = i.displayId||(i.id||'').split('___')[0];
      let cleanCode = rawId
        .replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/-COPY\d*$/i,'')
        .replace(/_inv$/i,'').trim();
      if(!cleanCode) return;
      const qty = parseNum(i.stock||0);
      const resolvedSub = i.subcategory || getItemSubcategory(i) || getItemSubcategory({id:cleanCode,desc:i.desc||'',category:'Productos Terminados'}) || 'Otros Terminados';
      if(!ptByCodeExcel[cleanCode]) ptByCodeExcel[cleanCode] = {
        id:cleanCode, desc:i.desc||'', unit:i.unit||'und',
        subcategory: resolvedSub, stock:0, warehouses:{}
      };
      const almNom = i.almacen || rawId.split('___')[1]?.replace(/-/g,' ') || '';
      // Keep highest stock per warehouse (SET, not accumulate)
      if(!ptByCodeExcel[cleanCode].warehouses[almNom] || qty > ptByCodeExcel[cleanCode].warehouses[almNom]) {
        ptByCodeExcel[cleanCode].warehouses[almNom] = qty;
      }
      // Prefer shorter, cleaner description (the one without ×dims× suffix)
      const curDesc = ptByCodeExcel[cleanCode].desc || '';
      const newDesc = i.desc || '';
      // Pick the desc that does NOT contain '×' (those are legacy format docs)
      if(newDesc && !newDesc.includes('×') && curDesc.includes('×')) {
        ptByCodeExcel[cleanCode].desc = newDesc;
      } else if(newDesc && !newDesc.includes('×') && newDesc.length >= curDesc.length) {
        ptByCodeExcel[cleanCode].desc = newDesc;
      }
      if((i.almacen||'').includes('ZI') && resolvedSub !== 'Otros Terminados') ptByCodeExcel[cleanCode].subcategory = resolvedSub;
    });
    Object.values(ptByCodeExcel).forEach(p => {
      const hasNamed = Object.keys(p.warehouses).some(a=>a.trim()!=='');
      if(hasNamed && p.warehouses['']!==undefined) delete p.warehouses[''];
      p.stock = Object.values(p.warehouses).reduce((s,v)=>s+v,0);
      // Final subcategory fallback using detectSubcategory on the code+desc
      if(!p.subcategory || p.subcategory==='Otros Terminados') {
        const detected = detectSubcategory(p.id, p.desc);
        if(detected) p.subcategory = detected;
      }
    });
    // Also FG production lots — deduplicate against ptByCodeExcel
    // Match by: exact code OR by desc similarity (FG categoria+dims may differ slightly from inventory ID)
    const existingPTCodes = new Set(Object.keys(ptByCodeExcel).map(k=>k.toUpperCase()));
    // Build a normalized description set for fuzzy matching
    const existingPTDescs = new Set(
      Object.values(ptByCodeExcel).map(p=>(p.desc||'').toUpperCase().replace(/[×x\s\-\.]/g,'').substring(0,20))
    );
    const fgPTExcel = (finishedGoodsInventory||[]).filter(fg=>parseNum(fg.kgProducidos)>0||parseNum(fg.millares)>0).map(fg => {
      const esTermo = fg.tipoProducto==='TERMOENCOGIBLE';
      const cleanCode = `FG-${(fg.categoria||fg.producto||'PT').replace(/[\s_\-\/\|]/g,'').substring(0,14).toUpperCase()}-${fg.ancho||0}x${fg.largo||0}x${fg.micras||0}`;
      const detectedSub = detectSubcategory(cleanCode, fg.categoria||fg.producto||'') || (esTermo?'Termoencogibles':'Bolsas Plásticas');
      const fgDesc = formatFGLabel(fg);
      const fgDescNorm = fgDesc.toUpperCase().replace(/[×x\s\-\.]/g,'').substring(0,20);
      return {id:cleanCode, desc:fgDesc, unit:esTermo?'KG':'Millares', subcategory:detectedSub, stock:esTermo?parseNum(fg.kgProducidos):parseNum(fg.millares), _descNorm:fgDescNorm};
    }).filter(fg =>
      !existingPTCodes.has(fg.id.toUpperCase()) &&
      !existingPTDescs.has(fg._descNorm)          // skip if matching desc already in inventory PT
    );

    // Final combined list — hard dedup by cleanCode (case-insensitive), keep highest stock
    const allPTExcelMap = {};
    [...Object.values(ptByCodeExcel), ...fgPTExcel].forEach(item => {
      const key = item.id.toUpperCase();
      if(!allPTExcelMap[key] || item.stock > allPTExcelMap[key].stock) {
        allPTExcelMap[key] = item;
      }
    });
    const allPTExcel = Object.values(allPTExcelMap);
    const SUB_ORDER_EXCEL = ['Bolsas Plásticas','Termoencogibles','Stretch Film','Cintas','Papel Kraft','Dispensadores','Empaques Flexibles','Otros Terminados'];
    const SUB_COLORS_EXCEL = {'Bolsas Plásticas':'#1d4ed8','Termoencogibles':'#15803d','Stretch Film':'#7c3aed','Cintas':'#92400e','Papel Kraft':'#78350f','Dispensadores':'#9d174d','Empaques Flexibles':'#4338ca','Otros Terminados':'#374151'};
    const ptSubGroupsExcel = {};
    allPTExcel.forEach(item => {
      const sub = item.subcategory || 'Otros Terminados';
      if(!ptSubGroupsExcel[sub]) ptSubGroupsExcel[sub] = [];
      ptSubGroupsExcel[sub].push(item);
    });
    const orderedSubsExcel = [...SUB_ORDER_EXCEL.filter(s=>ptSubGroupsExcel[s]),...Object.keys(ptSubGroupsExcel).filter(s=>!SUB_ORDER_EXCEL.includes(s))];

    if(allPTExcel.length > 0) {
      html += sectionHeader(`✅ PRODUCTOS TERMINADOS — ${allPTExcel.length} ARTÍCULOS CONSOLIDADOS`, '#065f46');
      orderedSubsExcel.forEach(sub => {
        const subItems = (ptSubGroupsExcel[sub]||[]).sort((a,b)=>a.id.localeCompare(b.id));
        const subColor = SUB_COLORS_EXCEL[sub]||'#374151';
        html += `<tr><td colspan="10" style="background:${subColor};color:#fff;font-weight:bold;padding:4px 8px;font-size:10px;">↳ ${sub.toUpperCase()} — ${subItems.length} artículo${subItems.length!==1?'s':''}</td></tr>`;
        subItems.forEach((item,i) => {
          const almLabel = item.warehouses ? Object.entries(item.warehouses).filter(([,q])=>q>0).map(([a,q])=>(a||'ZI').replace('ALMACEN ','')+': '+formatNum(q)).join(' | ') : '';
          html += `<tr style="${i%2===1?'background-color:#f0fff4':''}">
            <td style="font-weight:900;color:#065f46">${item.id}</td>
            <td>${(item.desc||'').toUpperCase()}</td>
            <td style="text-align:center">${item.unit||'und'}</td>
            <td style="text-align:right;font-weight:bold">${formatNum(item.stock)}</td>
            <td style="background-color:#ffffcc;text-align:center">${(item.warehouses||{})['ALMACEN ZI']>0?formatNum((item.warehouses||{})['ALMACEN ZI']||0):''}</td>
            <td style="background-color:#ffffcc;text-align:center">${(item.warehouses||{})['ALMACEN BQTO']>0?formatNum((item.warehouses||{})['ALMACEN BQTO']||0):''}</td>
            <td style="background-color:#ffffcc;text-align:center">${(item.warehouses||{})['ALMACEN C2']>0?formatNum((item.warehouses||{})['ALMACEN C2']||0):''}</td>
            <td style="background-color:#ffffcc;text-align:center">${(item.warehouses||{})['ALMACEN MCY']>0?formatNum((item.warehouses||{})['ALMACEN MCY']||0):''}</td>
            <td></td>
            <td style="font-size:9px;color:#6b7280">${almLabel}</td>
          </tr>`;
        });
      });
    }

    html += `</tbody></table>
    <div style="margin-top:40px">
      <p><strong>Realizado por:</strong> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <strong>Supervisado por:</strong></p>
      <p><strong>Firma:</strong> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <strong>Firma:</strong></p>
      <p><strong>Fecha:</strong> _______________ &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <strong>Fecha:</strong> _______________</p>
    </div></body></html>`;

    const blob = new Blob([html], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `Toma_Fisica_${today}.xls`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setDialog({ title: '✅ Exportación Exitosa', text: 'Formato de Toma Física descargado con todas las secciones: MP, Consumibles y Terminados.', type: 'alert' });
  };

  // ============================================================================
  // FUNCIONES DE SEGURIDAD - VALIDACIÓN DE CLAVE ADMIN
  // ============================================================================
  const requireAdminPassword = useCallback((action, actionName = 'esta acción') => {
    setAdminAction(() => action);
    setAdminActionName(actionName);
    setShowAdminModal(true);
    setAdminPassword('');
  }, []);

  const handleAdminValidation = () => {
    // Busca la clave real del usuario admin en la base de datos (o cualquier usuario Master)
    const adminUser = (systemUsers || []).find(u => u.role === 'Master' || u.username === 'admin');
    const validPassword = adminUser?.password || ADMIN_PASSWORD;
    if (adminPassword === validPassword) {
      setShowAdminModal(false);
      if (adminAction) {
        adminAction();
      }
      setAdminAction(null);
      setAdminPassword('');
      setAdminActionName('');
    } else {
      setDialog({ 
        title: 'Error de Autenticación', 
        text: `La clave admin es incorrecta. Use la misma clave del usuario administrador del sistema.`, 
        type: 'alert' 
      });
      setAdminPassword('');
    }
  };

  const cancelAdminModal = useCallback(() => {
    setShowAdminModal(false);
    setAdminPassword('');
    setAdminAction(null);
    setAdminActionName('');
  }, []);

  // INICIO DE SESIÓN
  const [_sessionId] = useState(() => Math.random().toString(36).substring(2)+Date.now());
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [pwaInstallAvailable, setPwaInstallAvailable] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [showUpdateBanner, setShowUpdateBanner] = useState(false);

  // PWA install prompt + online status listeners
  useEffect(() => {
    const onInstall = () => setPwaInstallAvailable(true);
    const onOnline  = () => setIsOnline(true);
    const onOffline = () => setIsOnline(false);
    window.addEventListener('pwa-install-available', onInstall);
    window.addEventListener('online', onOnline);
    window.addEventListener('offline', onOffline);
    window.__showUpdateBanner = () => setShowUpdateBanner(true);
    return () => {
      window.removeEventListener('pwa-install-available', onInstall);
      window.removeEventListener('online', onOnline);
      window.removeEventListener('offline', onOffline);
    };
  }, []);

  const handlePWAInstall = async () => {
    if (!window.__pwaInstallPrompt) return;
    window.__pwaInstallPrompt.prompt();
    const result = await window.__pwaInstallPrompt.userChoice;
    if (result.outcome === 'accepted') setPwaInstallAvailable(false);
  };

  // ── RESTORE 7 FG products to Inventario General PT + ALMACEN ZI ──
  useEffect(() => {
    if(!inventory || !appUser || sessionStorage.getItem('fg_restore_v3')==='done') return;
    const FG_PRODUCTS = [{'id': 'FG-EMBUTIDOS2KIRI-53x83x0.012', 'desc': 'EMBUTIDOS 2 KIRI - 53X83X12MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-VENILACBOLSA25-53x91x0.020', 'desc': 'VENILAC - BOLSA 25KG - 53X91X20MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-VENILACBOLSA12-37x75x0.010', 'desc': 'VENILAC - BOLSA 12KG - 37X75X10MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-AFSGRIS-60x82x0.030', 'desc': 'AFS GRIS 60X82X30MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-EMBUTIDO1KIRI2-28x75x0.012', 'desc': 'EMBUTIDO 1 - KIRI 28X75X12MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-PAÑALKIRI-60x75x0.004', 'desc': 'PAÑAL-KIRI 60X75X4MIC', 'subcategory': 'Bolsas Plásticas'}, {'id': 'FG-TERMOPINTURASD-70x0x0.012', 'desc': 'TERMO - PINTURAS DEL CARIBE 70X12MIC', 'subcategory': 'Termoencogibles'}];
    const doRestore = async () => {
      let restored = 0;
      for(const prod of FG_PRODUCTS) {
        const docId = `${prod.id}___ALMACEN-ZI`;
        const exists = (inventory||[]).some(i=>i.id===docId||(i.id||'').split('___')[0]===prod.id);
        if(!exists) {
          try {
            await setDoc(getDocRef('inventory', docId), {
              id: docId, displayId: prod.id, desc: prod.desc,
              category: 'Productos Terminados', subcategory: prod.subcategory,
              almacen: 'ALMACEN ZI', unit: prod.subcategory==='Termoencogibles'?'KG':'Millares',
              stock: 0, cost: 0, timestamp: Date.now()
            });
            restored++;
          } catch(e) {}
        }
      }
      sessionStorage.setItem('fg_restore_v3','done');
    };
    doRestore();
  }, [inventory, appUser]);


  // ── AUTO-CORRECCIÓN (sin botones): refleja FG Producción en el catálogo de PT ──
  // Toma la existencia y el costo que ya están en "Productos Terminados (FG Producción)"
  // y los carga en los documentos de inventario que el catálogo / almacén / toma física
  // / movimientos usan, para que dejen de aparecer en 0. Se ejecuta sola, una vez.
  //   • Solo rellena documentos que estén en 0 (no toca los que ya tienen existencia, p.ej. CHUPETA).
  //   • Crea los que faltan (p.ej. VENILAC - TERMO).
  //   • Como toma el saldo ACTUAL de FG Producción, nunca restaura lo ya facturado.
  useEffect(() => {
    if(!inventory || !finishedGoodsInventory || !appUser) return;
    if(sessionStorage.getItem('auto_fg_mirror_v3')==='done') return;
    sessionStorage.setItem('auto_fg_mirror_v3','done');

    const r2 = (n) => Math.round(parseNum(n)*100)/100;
    const dimsFromCode = (code) => {
      const cc=String(code||'').split('___')[0].replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/_inv$/i,'').trim();
      const seg=cc.split('-').pop()||'';
      const p=seg.toLowerCase().split('x').map(x=>parseFloat(x)||0);
      return { ancho:p[0]||0, largo:p[1]||0 };
    };

    const doMirror = async () => {
      try {
        // 1) Agrupar FG Producción por tipo + ancho + largo (saldo actual y costo)
        const groups = {}; // key -> {esTermo, qty, costTotal, sample}
        (finishedGoodsInventory||[]).forEach(fg => {
          const esTermo = fg.tipoProducto === 'TERMOENCOGIBLE';
          const entregado = fg.status === 'ENTREGADO';
          const qty = entregado ? 0 : (esTermo ? parseNum(fg.kgProducidos) : parseNum(fg.millares));
          if(qty <= 0) return;
          const cu = esTermo ? parseNum(fg.costoUnitario||0) : parseNum(fg.costoUnitarioMillar||0);
          const key = `${esTermo?'T':'B'}|${r2(fg.ancho)}|${r2(fg.largo)}`;
          if(!groups[key]) groups[key] = { esTermo, qty:0, costTotal:0, sample:fg };
          groups[key].qty += qty;
          groups[key].costTotal += qty*cu;
        });

        for(const key of Object.keys(groups)){
          const g = groups[key];
          const fg = g.sample;
          const qtyTot = g.qty;
          const costUnit = qtyTot>0 ? g.costTotal/qtyTot : 0;

          // 2) Buscar el documento de inventario que corresponde (mismo tipo + ancho + largo)
          const ptDocs = (inventory||[]).filter(i => i.category==='Productos Terminados' && i.activo!==false);
          const doc = ptDocs.find(i => {
            const esT = (i.subcategory==='Termoencogibles') || (i.unit||'').toLowerCase()==='kg';
            const d = dimsFromCode(i.displayId||i.id);
            return esT===g.esTermo && r2(d.ancho)===r2(fg.ancho) && r2(d.largo)===r2(fg.largo);
          });

          if(doc){
            // Solo rellenar si está en 0 (no pisar los que ya tienen existencia correcta)
            if(parseNum(doc.stock) > 0) continue;
            await setDoc(getDocRef('inventory', doc.id), {
              ...doc, stock: qtyTot, cost: parseNum(doc.cost)>0 ? parseNum(doc.cost) : costUnit,
              timestamp: Date.now(), updatedAt: getTodayDate()
            }, { merge:true });
          } else {
            // 3) Crear el documento que falta (p.ej. VENILAC - TERMO)
            const desc = formatFGLabel(fg) || fg.producto || 'Producto';
            const catShort = (fg.categoria||fg.producto||'PT').toUpperCase().replace(/[\s\/\-&]+/g,'').substring(0,18);
            const w=parseFloat(fg.ancho||0), l=parseFloat(fg.largo||0), m=parseFloat(fg.micras||0);
            const cleanCode = `FG-${catShort}-${w}x${l}x${m}`;
            const newId = `${cleanCode}___ALMACEN-ZI`;
            // Evitar duplicar si por alguna razón ya existe ese id
            if((inventory||[]).some(i => i.id===newId || (i.id||'').split('___')[0]===cleanCode)) continue;
            await setDoc(getDocRef('inventory', newId), {
              id:newId, displayId:cleanCode, desc,
              category:'Productos Terminados',
              subcategory: g.esTermo?'Termoencogibles':'Bolsas Plásticas',
              unit: g.esTermo?'KG':'Millares',
              stock: qtyTot, cost: costUnit,
              almacen:'ALMACEN ZI', activo:true,
              timestamp:Date.now(), updatedAt:getTodayDate()
            });
          }
        }
      } catch(e){ console.error('Auto-mirror FG error:', e); }
    };
    doMirror();
  }, [inventory, finishedGoodsInventory, appUser]);


  // ── ONE-TIME cleanup: FG duplicate docs only ──
  useEffect(() => {
    if(!inventory || !appUser || sessionStorage.getItem('cleanup_mp0240_fg_v1')==='done') return;
    const doCleanup = async () => {
      try {
        const b = writeBatch(db);
        let count = 0;
        // (MP-0240 no longer deleted — user re-created it)

        // Delete FG PT duplicate docs
        // The 7 affected codes
        const FG_CODES = [
          'FG-TERMOPINTURASD-70x0x0.012','FG-AFSGRIS-60x82x0.030',
          'FG-EMBUTIDO1KIRI2-28x75x0.012','FG-EMBUTIDOS2KIRI-53x83x0.012',
          'FG-PAÑALKIRI-60x75x0.004','FG-VENILACBOLSA12-37x75x0.010',
          'FG-VENILACBOLSA25-53x91x0.020'
        ];
        FG_CODES.forEach(code => {
          // All docs whose cleanCode matches
          const docs = (inventory||[]).filter(i => {
            const cc = (i.displayId||(i.id||'').split('___')[0])
              .replace(/-RESTORE$/i,'').replace(/-BACKUP$/i,'').replace(/_inv$/i,'').trim();
            return cc === code;
          });
          if(docs.length <= 1) return;
          // Group by almacén
          const byAlm = {};
          docs.forEach(d => {
            const alm = d.almacen || (d.id||'').split('___')[1]?.replace(/-/g,' ') || 'ALMACEN ZI';
            if(!byAlm[alm]) byAlm[alm] = [];
            byAlm[alm].push(d);
          });
          Object.values(byAlm).forEach(almDocs => {
            if(almDocs.length <= 1) return;
            // Sort: keep highest stock, then most recent timestamp
            almDocs.sort((a,b) => parseNum(b.stock)-parseNum(a.stock) || (b.timestamp||0)-(a.timestamp||0));
            // Delete all but first (highest stock)
            almDocs.slice(1).forEach(d => { b.delete(getDocRef('inventory', d.id)); count++; });
          });
        });

        if(count > 0) await b.commit();
        sessionStorage.setItem('cleanup_mp0240_fg_v1','done');
      } catch(e) {
        console.error('Cleanup error:', e);
      }
    };
    doCleanup();
  }, [inventory, appUser]);

  useEffect(() => {
    if(!appUser || sessionStorage.getItem('del_req_00017')==='done') return;
    const doDelete = async () => {
      try {
        // Find all docs with id containing 00017 or op number 17
        const toDelete = (requirements||[]).filter(r => {
          const rid = String(r.id||'').replace('OP-','');
          return rid === '00017' || rid === '17' || r.id === 'OP-00017' || r.id === 'OP-17';
        });
        if(toDelete.length > 0) {
          const b = writeBatch(db);
          toDelete.forEach(r => b.delete(getDocRef('requirements', r.id)));
          await b.commit();
        }
        sessionStorage.setItem('del_req_00017','done');
      } catch(e) { console.error('Delete req 00017:', e); }
    };
    doDelete();
  }, [requirements, appUser]);

  // Heartbeat: update lastPing every 30 seconds to keep session alive
  useEffect(() => {
    if (!appUser || appUser.role === 'Master') return;
    const pingFn = () => {
      setDoc(getDocRef('activeSessions', appUser.username), { lastPing: Date.now() }, { merge: true }).catch(()=>{});
    };
    pingFn();
    const interval = setInterval(pingFn, 30000);
    const cleanup = async () => {
      clearInterval(interval);
      try { await deleteDoc(getDocRef('activeSessions', appUser.username)); } catch(e){}
    };
    window.addEventListener('beforeunload', cleanup);
    return () => { clearInterval(interval); window.removeEventListener('beforeunload', cleanup); };
  }, [appUser]);
  const handleLogin = async (e) => {
    e.preventDefault();
    const user = loginData.username.toLowerCase().trim();
    const pass = loginData.password.trim();

    // Hardcoded master fallback — always works even if Firestore user was deleted
    const MASTER_USER = 'administrador';
    const MASTER_PASS = 'Supply2026.Admin';
    let foundUser = systemUsers.find(u =>
      (u.username||'').toLowerCase().trim() === user && u.password === pass
    );
    if (!foundUser && user === MASTER_USER && pass === MASTER_PASS) {
      foundUser = {
        id: 'Administrador', username: 'Administrador', password: MASTER_PASS,
        name: 'Administrador General', role: 'Master',
        permissions: { ventas:true, ventas_ops:true, ventas_facturacion:true, ventas_directorio:true, produccion:true, produccion_proyeccion:true, produccion_ordenes:true, produccion_activa:true, produccion_historial:true, formulas:true, inventario:true, inventario_solicitudes:true, inventario_catalogo:true, inventario_movimientos:true, inventario_kardex:true, inv_almacen:true, inv_terminados:true, inv_operaciones:true, simulador:true, costos:true, costos_operativos:true, costos_reportes:true, kpi:true, configuracion:true, auditoria:true }
      };
      // Recreate in Firestore silently
      try { await setDoc(getDocRef('users','Administrador'), {...foundUser, timestamp: Date.now()}); } catch(e){}
    }
    if (!foundUser) return setLoginError('Credenciales incorrectas. Intente nuevamente.');
    // Session lock: check if already active on another device (except Master)
    if (foundUser.role !== 'Master') {
      try {
        const { getDoc: gd } = await import('firebase/firestore');
        const sessDoc = await gd(getDocRef('activeSessions', foundUser.username));
        if (sessDoc.exists()) {
          const sess = sessDoc.data();
          if (sess.sessionId && sess.sessionId !== _sessionId && (Date.now() - (sess.lastPing||0)) < 90000) {
            return setLoginError(`⚠ El usuario "${foundUser.username}" ya está activo en otro dispositivo. Cierre primero esa sesión.`);
          }
        }
        await setDoc(getDocRef('activeSessions', foundUser.username), {
          sessionId: _sessionId, username: foundUser.username, name: foundUser.name,
          role: foundUser.role, loginAt: Date.now(), lastPing: Date.now()
        });
      } catch(e) { /* session check failed gracefully */ }
    }
    // Log login activity
    try {
      await addDoc(getColRef('userActivity'), {
        username: foundUser.username, name: foundUser.name, action: 'LOGIN',
        module: 'Sistema', details: 'Inicio de sesión',
        timestamp: Date.now(), date: getTodayDate()
      });
    } catch(e) {}
    setAppUser({ ...foundUser, _sessionId });
    setLoginError('');
  };
