  const handleSaveUser = async (e) => {
    e.preventDefault();
    if (!newUserForm.username || !newUserForm.password) return setDialog({title:'Aviso', text:'Usuario y contraseña requeridos.', type:'alert'});
    const newUserId = newUserForm.username.toLowerCase().trim();
    try {
      const batch = writeBatch(db);
      // Si estamos editando Y el nombre de usuario cambió
      if (editingUserId && originalUsername && originalUsername !== newUserId) {
        const existingUserDoc = (systemUsers || []).find(u => u.username === newUserId);
        if (existingUserDoc) return setDialog({title: 'Error', text: `El usuario '${newUserId}' ya existe. Elija otro.`, type: 'alert'});
        // Borrar documento viejo
        batch.delete(getDocRef('users', originalUsername));
      }
      // Guardar documento con el ID correcto
      // IMPORTANTE: excluir el campo 'id' del objeto guardado para evitar conflictos
      const { id: _skipId, ...formToSave } = newUserForm;
      batch.set(getDocRef('users', newUserId), { ...formToSave, username: newUserId });
      await batch.commit();
      setNewUserForm(initialUserForm);
      setEditingUserId(null);
      setOriginalUsername(null);
      setDialog({title: 'Éxito', text: (editingUserId && originalUsername !== newUserId) ? 'Usuario actualizado y renombrado.' : 'Usuario guardado.', type: 'alert'});
    } catch(err) { setDialog({title: 'Error', text: err.message, type: 'alert'}); }
  };
  const startEditUser = (u) => {
    const defaultPerms = generateDefaultPermissions();
    // Fusionar permisos por defecto con los del usuario (asegura que módulos nuevos aparezcan en false)
    const mergedPerms = { ...defaultPerms, ...(u.permissions || {}) };
    setEditingUserId(u.username);
    setOriginalUsername(u.username);
    setNewUserForm({ ...u, permissions: mergedPerms });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };
  const handleDeleteUser = (usernameOrId) => {
    // Buscar el usuario real en la lista (por username o por id)
    const targetUser = (systemUsers || []).find(u => u.username === usernameOrId || u.id === usernameOrId);
    const targetUsername = targetUser?.username || usernameOrId;
    const targetDocId = targetUser?.id || targetUser?.username || usernameOrId;

    // No puede eliminar su propio usuario
    if (targetUsername === appUser?.username) {
      return setDialog({ title: 'Acción Denegada', text: 'No puedes eliminar tu propio usuario activo.', type: 'alert' });
    }
    // No puede eliminar el único administrador Master
    const masterUsers = (systemUsers || []).filter(u => u.role === 'Master');
    if ((targetUser?.role === 'Master') && masterUsers.length <= 1) {
      return setDialog({ title: 'Acción Denegada', text: 'No puedes eliminar el único administrador del sistema. Primero crea otro usuario Master.', type: 'alert' });
    }
    if (!targetUser) {
      return setDialog({ title: 'Error', text: `Usuario "${usernameOrId}" no encontrado.`, type: 'alert' });
    }
    setDialog({
      title: 'Eliminar Usuario',
      text: `¿Desea eliminar el acceso de "${targetUser.name || targetUsername}" (usuario: ${targetUsername})?`,
      type: 'confirm',
      onConfirm: async () => {
        try {
          await deleteDoc(getDocRef('users', targetDocId));
          setDialog({ title: '✅ Eliminado', text: `Usuario "${targetUsername}" eliminado correctamente.`, type: 'alert' });
        } catch(err) {
          setDialog({ title: 'Error', text: err.message, type: 'alert' });
        }
      }
    });
  };

  // ============================================================================
  // FIX 7: Corrección de datos de Productos Terminados (one-time, idempotent)
  // ============================================================================
  useEffect(() => {
    if (!appUser || appUser.role !== 'Master' || !finishedGoodsInventory.length) return;
    const runFix7 = async () => {
      try {
        let batchOps = [];
        const flush = async () => {
          if (!batchOps.length) return;
          const b = writeBatch(db);
          batchOps.forEach(op => op.type === 'delete' ? b.delete(op.ref) : b.update(op.ref, op.data));
          await b.commit(); batchOps = [];
        };
        for (const fg of finishedGoodsInventory) {
          const prod = (fg.producto || '').toUpperCase();
          // 1. Eliminar TODOS los registros con 9X14X6MIC en el nombre
          if (prod.includes('9X14X6MIC')) {
            batchOps.push({ type: 'delete', ref: getDocRef('finishedGoodsInventory', fg.id) });
            if (batchOps.length >= 400) await flush();
            continue;
          }
          // 2. Corregir 60X82X30MIC → nombre limpio, stock real 8.76, costo $287.21/Mill.
          if (prod.includes('60X82X30MIC') && !fg._fix7Applied) {
            batchOps.push({ type: 'update', ref: getDocRef('finishedGoodsInventory', fg.id), data: {
              producto: 'AFS GRIS 60X82X30MIC',
              millares: 8.76,
              kgProducidos: 0,
              costoUnitarioMillar: 287.21,
              costoUnitario: 287.21,
              tipoProducto: 'BOLSAS',
              _fix7Applied: true
            }});
            if (batchOps.length >= 400) await flush();
          }
        }
        await flush();
        // 3. Eliminar movimientos de Kardex con nombre corrupto del 60X82
        const badMovs = (invMovements||[]).filter(m => {
          const d = (m.itemDesc||'').toUpperCase();
          return d.includes('60X82X30MIC') && (d.includes('60X82X30MIC - AFS') || d.includes('AFS GRIS 60X82X30MIC - 60X82'));
        });
        if (badMovs.length > 0) {
          const bm = writeBatch(db);
          badMovs.forEach(m => bm.delete(getDocRef('inventoryMovements', m.id)));
          await bm.commit();
        }
      } catch(e) { console.warn('Fix7:', e.message); }
    };
    runFix7();
  }, [appUser, finishedGoodsInventory.length]);

  // ============================================================================
  // FG PRODUCT EDIT HANDLER
  // ============================================================================
  const handleSaveFGEdit = async () => {
    if(!editingFG) return;
    try {
      const newNombre = fgEditForm.producto.toUpperCase().trim() || editingFG.producto;
      const esTermo = editingFG.tipoProducto === 'TERMOENCOGIBLE';
      const grp = editingFG._group;
      const lotesToUpdate = grp ? grp.lotes : [editingFG];
      const batch = writeBatch(db);
      for(const fg of lotesToUpdate) {
        const isFirst = fg.id === lotesToUpdate[0].id;
        // FIX: save both producto AND categoria so description persists correctly
        const upd = { producto: newNombre, categoria: newNombre };
        const newCostoMillar = fgEditForm.costoUnitarioMillar !== '' ? parseNum(fgEditForm.costoUnitarioMillar) : null;
        const newCostoKg = fgEditForm.costoUnitario !== '' ? parseNum(fgEditForm.costoUnitario) : null;
        if(newCostoMillar !== null) upd.costoUnitarioMillar = newCostoMillar;
        if(newCostoKg !== null) upd.costoUnitario = newCostoKg;
        if(isFirst) {
          if(!esTermo && fgEditForm.millares !== '') {
            const newTotal = parseNum(fgEditForm.millares);
            upd.millares = newTotal;
            upd.millaresOrigen = Math.max(newTotal, parseNum(fg.millaresOrigen || 0));
          }
          if(esTermo && fgEditForm.kgProducidos !== '') {
            const newTotal = parseNum(fgEditForm.kgProducidos);
            upd.kgProducidos = newTotal;
            upd.kgProducidosOrigen = Math.max(newTotal, parseNum(fg.kgProducidosOrigen || 0));
          }
        } else {
          upd.millares = 0;
          upd.kgProducidos = 0;
        }
        batch.update(getDocRef('finishedGoodsInventory', fg.id), upd);
      }
      await batch.commit();
      setEditingFG(null);
      setDialog({ title: '✅ Actualizado', text: `"${newNombre}" guardado correctamente en todos los lotes.`, type: 'alert' });
    } catch(err) { setDialog({ title: 'Error al guardar', text: err.message, type: 'alert' }); }
  };


  // ============================================================================
  // HANDLER: EDITAR STOCK/COSTO DE PRODUCTO EN ALMACÉN ESPECÍFICO
  // Actualiza directamente el documento Firebase del almacén y registra movimiento
  // ============================================================================
  // ============================================================================
  // SINCRONIZAR COSTOS — equipara el costo promedio de cada producto en todos sus almacenes
  // ============================================================================
  const handleSyncAllCosts = async () => {
    setDialog({ title: 'Sincronizar Costos', text: '¿Desea actualizar el costo unitario de TODOS los productos en todos los almacenes para que coincidan con el costo promedio ponderado mostrado en Inventario General? Esta acción es irreversible.', type: 'confirm', onConfirm: async () => {
      try {
        // Group all inventory docs by cleanId, compute weighted average
        const groups = {};
        for (const i of (inventory||[])) {
          const cleanId = i.displayId || (i.id||'').split('___')[0];
          if (!groups[cleanId]) groups[cleanId] = { totalVal: 0, totalStock: 0, docs: [] };
          const stk = parseNum(i.stock||0);
          const cst = parseNum(i.cost||0);
          groups[cleanId].totalVal += stk * cst;
          groups[cleanId].totalStock += stk;
          groups[cleanId].docs.push(i);
        }
        // Update all docs with the weighted average cost
        const batchSize = 400;
        let ops = [];
        for (const [cleanId, g] of Object.entries(groups)) {
          if (g.docs.length <= 1) continue; // single warehouse: already consistent
          // FIX 8: Use the cost from the most recently updated document (direct substitution)
          // FIX 2: Use weighted average = the cost Inventario General shows
          // This way after sync, Gestión de Almacenes matches exactly Inventario General
          const avgCost = g.totalStock > 0 ? g.totalVal / g.totalStock : (g.docs[0]?.cost || 0);
          if (avgCost <= 0) continue;
          for (const doc of g.docs) {
            const docCost = parseNum(doc.cost||0);
            if (Math.abs(docCost - avgCost) > 0.001) ops.push({ id: doc.id, cost: avgCost });
          }
        }
        // Write in batches
        let count = 0;
        for (let i = 0; i < ops.length; i += batchSize) {
          const chunk = ops.slice(i, i + batchSize);
          const b = writeBatch(db);
          chunk.forEach(op => b.set(getDocRef('inventory', op.id), { cost: op.cost }, { merge: true }));
          await b.commit();
          count += chunk.length;
        }
        if (count === 0) {
          setDialog({ title: 'ℹ️ Sin cambios', text: 'Todos los almacenes ya tienen el mismo costo. No hubo nada que actualizar.', type: 'alert' });
        } else {
          setDialog({ title: '✅ Costos Igualados', text: `${count} documento(s) actualizados. Todos los almacenes ahora usan el mismo costo por producto.`, type: 'alert' });
        }
      } catch(err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
    }});
  };

  const handleSaveAlmacenItem = async () => {
    if (!editingAlmacenItem) return;
    const newStock = parseNum(almacenEditForm.stock);
    const newCost  = parseNum(almacenEditForm.cost);
    const prevStock = parseNum(editingAlmacenItem.stock || 0);
    const cleanIdEdit = editingAlmacenItem.displayId || (editingAlmacenItem.id||'').split('___')[0];
    const almacenEdit = editingAlmacenItem.almacen || 'ALMACEN ZI';
    // Use _realId (set during grouping) — this is the actual Firebase document ID
    const realDocId = editingAlmacenItem._realId || (() => {
      const found = (inventory||[]).find(i => {
        const cid = i.displayId || (i.id||'').split('___')[0];
        return cid === cleanIdEdit && (i.almacen || 'ALMACEN ZI') === almacenEdit;
      });
      return found?.id || (cleanIdEdit + '___' + almacenEdit.replace(/\s+/g, '-'));
    })();
    try {
      const hasCostChange = almacenEditForm.cost !== '';
      const hasStockChange = almacenEditForm.stock !== '';
      if (!hasCostChange && !hasStockChange) return;
      // FIX 8: Cost = DIRECT SUBSTITUTION to ALL warehouses (no averaging, no division)
      // Stock = only the specific warehouse being edited
      // DESC/SUBCATEGORY: propagate to ALL warehouse docs via batch (Fix Issue #2)
      const hasDescChange = almacenEditForm.desc && almacenEditForm.desc !== editingAlmacenItem.desc;
      const hasSubcatChange = almacenEditForm.subcategory && almacenEditForm.subcategory !== (editingAlmacenItem.subcategory||'');
      if(hasDescChange || hasSubcatChange) {
        // Propagate to all warehouse docs with same displayId
        const allWarehouseDocs = (inventory||[]).filter(i=>{
          const cid = i.displayId||(i.id||'').split('___')[0];
          return cid === cleanIdEdit;
        });
        if(allWarehouseDocs.length > 1) {
          const batchProp = writeBatch(db);
          allWarehouseDocs.forEach(wDoc=>{
            const updates = {};
            if(hasDescChange) updates.desc = almacenEditForm.desc.toUpperCase();
            if(hasSubcatChange) updates.subcategory = almacenEditForm.subcategory;
            batchProp.update(getDocRef('inventory', wDoc.id), updates);
          });
          await batchProp.commit();
        }
      }
      if (hasCostChange) {
        const allDocs = (inventory||[]).filter(i => (i.displayId || (i.id||'').split('___')[0]) === cleanIdEdit);
        if (allDocs.length > 0) {
          const b = writeBatch(db);
          allDocs.forEach(d => {
            const upd = { cost: newCost, timestamp: Date.now() };
            if (almacenEditForm.desc) upd.desc = almacenEditForm.desc.toUpperCase();
            if (almacenEditForm.subcategory !== undefined) upd.subcategory = almacenEditForm.subcategory;
            if (d.id === realDocId && hasStockChange) upd.stock = newStock;
            b.set(getDocRef('inventory', d.id), upd, { merge: true });
          });
          await b.commit();
        } else {
          // No existing docs — create/update the specific warehouse doc
          const upd = { cost: newCost, timestamp: Date.now() };
          if (hasStockChange) upd.stock = newStock;
          await setDoc(getDocRef('inventory', realDocId), upd, { merge: true });
        }
      } else {
        // Only stock — update just this warehouse
        await setDoc(getDocRef('inventory', realDocId), { stock: newStock, timestamp: Date.now() }, { merge: true });
      }
      // Kardex entry for stock change
      const diff = hasStockChange ? newStock - prevStock : 0;
      if (Math.abs(diff) > 0.001) {
        await addDoc(getColRef('inventoryMovements'), {
          itemId: realDocId, itemDesc: editingAlmacenItem.desc, almacen: almacenEdit,
          type: diff > 0 ? 'ENTRADA' : 'SALIDA', qty: Math.abs(diff),
          unitCost: hasCostChange ? newCost : parseNum(editingAlmacenItem.cost||0),
          totalValue: Math.abs(diff) * (hasCostChange ? newCost : parseNum(editingAlmacenItem.cost||0)),
          previousStock: prevStock, newStock,
          docRef: 'AJUSTE MANUAL ALMACÉN', notes: `Gestión de Almacenes — ${almacenEdit}`,
          date: getTodayDate(), user: appUser?.name || 'Admin', timestamp: Date.now()
        });
      }
      setEditingAlmacenItem(null);
      setDialog({ title: '✅ Actualizado', text: `${cleanIdEdit}: ${hasCostChange?`costo $${formatNum(newCost)} aplicado en TODOS los almacenes. `:''}${hasStockChange?`stock ${formatNum(newStock)} en ${almacenEdit}.`:''}`, type: 'alert' });
    } catch (err) { setDialog({ title: 'Error', text: err.message, type: 'alert' }); }
  };;

